import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.authentication.logout.LogoutSuccessHandler;
import org.springframework.stereotype.Controller;
import org.springframework.ui.ModelMap;
import org.springframework.web.bind.annotation.GetMapping;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

@Controller
public class LogoutController implements LogoutSuccessHandler {

    @Autowired
    private HttpServletRequest request;

    @GetMapping("/logout")
    public String logoutPage(ModelMap model) {
        return "redirect:logoutSuccess";
    }

    @Override
    public String onLogoutSuccess(HttpServletRequest request, HttpServletResponse response, Authentication authentication) throws IOException, ServletException {
        String next = request.getParameter("next");
        if (next != null && !next.isEmpty()) {
            response.sendRedirect(next);
        } else {
            response.sendRedirect("/home"); // default redirect URL
        }
        return null;
    }
}